import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';
import ArtisanCard from '../components/ArtisanCard';

const Construction = () => {
    const { categoryName } = useParams(); 
    const [artisans, setArtisans] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        setLoading(true);
        axios.get(`http://localhost:5000/api/artisans?category=${categoryName}`)
            .then(res => {
                setArtisans(res.data);
                setLoading(false);
            })
            .catch(err => {
                console.error("Erreur chargement artisans:", err);
                setLoading(false);
            });
    }, [categoryName]); 

    if (loading) return <div className="text-center py-5">Chargement des artisans...</div>;

    return (
        <div className="container py-4">
            <h2 className="mb-4 text-primary">Artisans : {categoryName}</h2>
            
            {artisans.length > 0 ? (
                <div className="row">
                    {artisans.map(artisan => (
                        <ArtisanCard key={artisan.id} artisan={artisan} />
                    ))}
                </div>
            ) : (
                <div className="alert alert-info">
                    Aucun artisan trouvé dans la catégorie {categoryName}.
                </div>
            )}
        </div>
    );
};

export default Construction;
